using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 behavioral change: ZipArchiveEntry now respects the UTF-8 flag,
        // which changes how non-ASCII entry names are encoded. The legacy Java
        // consumer expects Shift-JIS, so force that encoding to avoid setting
        // the UTF-8 flag in entry headers.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");

        using var stream = new FileStream("data.zip", FileMode.Create);
        using var archive = new ZipArchive(stream, ZipArchiveMode.Create, leaveOpen: false, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 behavioral change: [FromKeyedServices] no longer falls back to
// non-keyed registrations — it throws InvalidOperationException instead.
// Register as a keyed service to match the controller's attribute.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

